const SESSION_SECRET = process.env.SESSION_SECRET || crypto.randomBytes(64).toString('hex');
const ALGORITHM = 'aes-256-gcm';
const SIGNING_KEY = crypto.createHash('sha256').update(SESSION_SECRET).digest();

// Permission definitions - logic lives on the server, NOT in the cookie
const PermissionSystem = {
  accessLevels: ['read', 'write', 'admin', 'superadmin'],

  createPermissions(permissionData) {
    const permissions = { ...permissionData };

    return {
      get roles() {
        return [...(permissions.roles || [])];
      },
      get level() {
        return permissions.level || 0;
      },
      hasRole(role) {
        return (permissions.roles || []).includes(role);
      },
      hasMinLevel(requiredLevel) {
        const requiredIndex = PermissionSystem.accessLevels.indexOf(requiredLevel);
        return permissions.level >= requiredIndex;
      },
      canAccess(resource) {
        const resourcePermissions = permissions.resourceAccess || {};
        return resourcePermissions[resource] === true;
      },
      toSerializable() {
        return { ...permissions };
      }
    };
  }
};

// Session class with getters/setters and computed properties
